output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?character ?label WHERE {
  ?character wdt:P1441 wd:Q189811 .
  ?character rdfs:label ?label .
  FILTER(LANG(?label) = "en")
  .
  OPTIONAL {
    ?character wdt:P106 ?occupation .
  }
  OPTIONAL {
    ?character wdt:P2333 ?socialClass .
  }
  VALUES ?nonWorkingOccupation {
    wd:Q486971 wd:Q6765892 wd:Q10830916 wd:Q6578573 wd:Q668 wd:Q43074
  }
  VALUES ?nonWorkingClass {
    wd:Q208599 wd:Q170296
  }
  FILTER((BOUND(?occupation) && ?occupation = ?nonWorkingOccupation) ||(BOUND(?socialClass) && ?socialClass = ?nonWorkingClass))
}
ORDER BY ?label
LIMIT 10

