  wd:Q189811 wdt:P674 ?character.
  OPTIONAL { ?character wdt:P106 ?occupation. }
  OPTIONAL { ?character wdt:P2333 ?socialClass. }
  VALUES ?nonWorkingClassOccupation {
    wd:Q486971   # lawyer
    wd:Q6765892  # clergyman
    wd:Q42539    # noble
    wd:Q6578573  # landowner
